#include <iostream>
#include <vector>

using namespace std;

int find(vector<int> &parent, int x)
{
    if (parent[x] != x)
    {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

bool unite(vector<int> &parent, int a, int b)
{
    int rootA = find(parent, a);
    int rootB = find(parent, b);

    if (rootA == rootB)
    {
        return false; // already connected — adding this edge would create a CYCLE
    }

    parent[rootA] = rootB; // merge the two groups
    return true;
}

int main()
{
    int n = 5;
    vector<int> parent(n);
    for (int i = 0; i < n; i++) parent[i] = i;

    vector<pair<int, int>> edges = {{0, 1}, {1, 2}, {3, 4}, {0, 2}};

    for (auto &edge : edges)
    {
        if (unite(parent, edge.first, edge.second))
        {
            cout << "Union: " << edge.first << "-" << edge.second << endl;
        }
        else
        {
            cout << "Cycle detected: " << edge.first << "-" << edge.second << endl;
        }
    }

    return 0;
}

